class HomeScreen extends StatelessWidget {
  final AuthService authService;
  final VoidCallback onLogout;

  const HomeScreen({
    super.key,
    required this.authService,
    required this.onLogout,
  });

  Future<void> _handleLogout(BuildContext context) async {
    final confirm = await showDialog<bool>(
      context: context,
      builder: (context) => AlertDialog(
        title: const Text('Logout'),
        content: const Text('Are you sure you want to logout?'),
        actions: [
          TextButton(
            onPressed: () => Navigator.of(context).pop(false),
            child: const Text('Cancel'),
          ),
          FilledButton(
            onPressed: () => Navigator.of(context).pop(true),
            child: const Text('Logout'),
          ),
        ],
      ),
    );

    if (confirm == true) {
      await authService.logout();
      onLogout();
    }
  }

  Future<void> _toggleBiometric(BuildContext context, bool currentValue) async {
    if (!currentValue) {
      // Enabling biometric - verify with biometric first
      final success = await authService.authenticateWithBiometrics();
      if (success) {
        await authService.setBiometricEnabled(true);
        if (context.mounted) {
          ScaffoldMessenger.of(context).showSnackBar(
            const SnackBar(content: Text('Biometric authentication enabled')),
          );
        }
      }
    } else {
      await authService.setBiometricEnabled(false);
      if (context.mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(content: Text('Biometric authentication disabled')),
        );
      }
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('Home'),
        actions: [
          IconButton(
            icon: const Icon(Icons.logout),
            onPressed: () => _handleLogout(context),
          ),
        ],
      ),
      body: Center(
        child: Padding(
          padding: const EdgeInsets.all(24.0),
          child: Column(
            mainAxisAlignment: MainAxisAlignment.center,
            children: [
              Icon(
                Icons.check_circle_outline,
                size: 80,
                color: Theme.of(context).colorScheme.primary,
              ),
              const SizedBox(height: 24),
              Text(
                'Authentication Successful!',
                style: Theme.of(context).textTheme.headlineSmall?.copyWith(
                      fontWeight: FontWeight.bold,
                    ),
                textAlign: TextAlign.center,
              ),
              const SizedBox(height: 8),
              Text(
                'You are now securely logged in.',
                style: Theme.of(context).textTheme.bodyLarge?.copyWith(
                      color: Theme.of(context).colorScheme.onSurfaceVariant,
                    ),
                textAlign: TextAlign.center,
              ),
              const SizedBox(height: 48),
              FutureBuilder<bool>(
                future: authService.isBiometricAvailable(),
                builder: (context, biometricSnapshot) {
                  if (biometricSnapshot.data != true) {
                    return const SizedBox.shrink();
                  }
                  return FutureBuilder<bool>(
                    future: authService.isBiometricEnabled(),
                    builder: (context, enabledSnapshot) {
                      final isEnabled = enabledSnapshot.data ?? false;
                      return Card(
                        child: ListTile(
                          leading: const Icon(Icons.fingerprint),
                          title: const Text('Biometric Login'),
                          subtitle: Text(
                            isEnabled ? 'Enabled' : 'Disabled',
                          ),
                          trailing: Switch(
                            value: isEnabled,
                            onChanged: (value) {
                              _toggleBiometric(context, isEnabled);
                            },
                          ),
                        ),
                      );
                    },
                  );
                },
              ),
              const SizedBox(height: 24),
              OutlinedButton.icon(
                onPressed: () => _handleLogout(context),
                icon: const Icon(Icons.logout),
                label: const Text('Logout'),
                style: OutlinedButton.styleFrom(
                  padding: const EdgeInsets.symmetric(
                    horizontal: 32,
                    vertical: 16,
                  ),
                ),
              ),
            ],
          ),
        ),
      ),
    );
  }
}